import json, re
# Load UC-assigned patent records (those with 'UNIV CALIFORNIA')
uc_path = var_call_ip0VIxxQPAYpor7I60ZUMkDa
with open(uc_path, 'r') as f:
    uc_records = json.load(f)
# Extract publication_numbers from UC records: look in Patents_info and also in title_localized? We'll parse Patents_info
pub_pattern = re.compile(r"[A-Z]{2}-\d{4,}[A-Z0-9\-]*")
uc_pubnums = set()
for r in uc_records:
    pi = r.get('Patents_info','')
    for m in pub_pattern.findall(pi):
        uc_pubnums.add(m)
# Also some citation entries might reference plain US numbers without hyphen? But in dataset they seem to use hyphen format.

# Load all records that have citations (large file path)
all_with_citations_path = var_call_HxwxtUk3uNpafLTqE5P37yAw
with open(all_with_citations_path, 'r') as f:
    all_records = json.load(f)

# For each record in all_records, parse its citation list and check if any publication_number matches a UC pubnum
citing = []
# regex to extract assignee from Patents_info
assignee_patterns = [r'^(.*?)\s+holds\s+the', r'^(.*?)\s+is\s+assigned\s+to', r'^(.*?)\s+is\s+owned\s+by', r'^(.*?)\s+belongs\s+to', r'^(.*?)\s+is\s+belonging\s+to', r'^(.*?)\s+from\s+']
for r in all_records:
    cit_field = r.get('citation')
    if not cit_field:
        continue
    try:
        cit_list = json.loads(cit_field)
    except Exception:
        # try simple heuristic: if it's already a list
        cit_list = r.get('citation')
        if not isinstance(cit_list, list):
            continue
    matched = False
    for c in cit_list:
        pubnum = c.get('publication_number','') if isinstance(c, dict) else ''
        if pubnum and pubnum in uc_pubnums:
            matched = True
            break
    if not matched:
        continue
    # extract assignee from Patents_info
    pi = r.get('Patents_info','')
    assignee = None
    for pat in assignee_patterns:
        m = re.search(pat, pi, flags=re.IGNORECASE)
        if m:
            assignee = m.group(1).strip()
            break
    if not assignee:
        # fallback: take up to first comma or 'holds' if exists
        if 'holds' in pi:
            assignee = pi.split('holds')[0].strip()
        elif 'assigned to' in pi:
            assignee = pi.split('assigned to')[0].strip()
        else:
            # take first 5 words
            assignee = ' '.join(pi.split()[:5])
    # parse cpc field to find primary code
    primary_code = None
    cpc_field = r.get('cpc')
    if cpc_field:
        try:
            cpc_list = json.loads(cpc_field)
        except Exception:
            cpc_list = r.get('cpc')
        if isinstance(cpc_list, list):
            for e in cpc_list:
                try:
                    if isinstance(e, dict) and e.get('first'):
                        primary_code = e.get('code')
                        break
                except Exception:
                    continue
            if not primary_code and len(cpc_list)>0:
                first = cpc_list[0]
                if isinstance(first, dict):
                    primary_code = first.get('code')
    citing.append({'rowid': r.get('rowid'), 'assignee': assignee, 'primary_code': primary_code})

# Filter out UNIV CALIFORNIA assignees (case-insensitive)
out = [c for c in citing if c['assignee'] and 'UNIV CALIFORNIA' not in c['assignee'].upper()]
# Deduplicate by assignee and primary_code
seen = set()
uniq = []
for c in out:
    key = (c['assignee'], c['primary_code'])
    if key not in seen:
        seen.add(key)
        uniq.append(c)

import json as _json
print('__RESULT__:')
print(_json.dumps(uniq))

